using System;using System.Collections.Generic;public class Program{static string R(string s,int k){if(k<=1)return s;int[]c=new int[26],last=new int[26];for(int i=0;i<26;i++)last[i]=-1000000000;foreach(char ch in s)c[ch-'a']++;var outv=new List<char>();for(int p=0;p<s.Length;p++){int b=-1;for(int i=0;i<26;i++)if(c[i]>0&&p-last[i]>=k&&(b<0||c[i]>c[b]))b=i;if(b<0)return "";outv.Add((char)('a'+b));c[b]--;last[b]=p;}return new string(outv.ToArray());}public static void Main(){string[]d=Console.In.ReadToEnd().Split((char[])null,StringSplitOptions.RemoveEmptyEntries);if(d.Length==0)return;int idx=0,t=int.Parse(d[idx++]);var outv=new List<string>();for(int tc=0;tc<t;tc++){string s=d[idx++];int k=int.Parse(d[idx++]);outv.Add("\""+R(s,k)+"\"");}Console.Write(string.Join("\n\n",outv));}}
